import{c as t,Q as r,j as a,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Harness Engineering as Categorical Architecture","description":"","frontmatter":{"title":"Harness Engineering as Categorical Architecture","authors":"Bogdan Banu","published":"2026-05-12T00:00:00.000Z","source":"https://arxiv.org/abs/2605.12239"},"headers":[],"relativePath":"research/papers/2026-05-12-harness-engineering-categorical-architecture-2605-12239.md","filePath":"research/papers/2026-05-12-harness-engineering-categorical-architecture-2605-12239.md","lastUpdated":1779894392000}'),o={name:"research/papers/2026-05-12-harness-engineering-categorical-architecture-2605-12239.md"};function n(s,e,l,c,d,h){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="harness-engineering-as-categorical-architecture" tabindex="-1">Harness Engineering as Categorical Architecture <a class="header-anchor" href="#harness-engineering-as-categorical-architecture" aria-label="Permalink to &quot;Harness Engineering as Categorical Architecture&quot;">​</a></h1><p><strong>Authors</strong>: Bogdan Banu <strong>Published</strong>: May 12, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.12239" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.12239</a><strong>arXiv ID</strong>: 2605.12239 <strong>Categories</strong>: cs.PL, cs.AI, math.CT <strong>Code</strong>: <a href="https://github.com/operon-ai" target="_blank" rel="noreferrer">https://github.com/operon-ai</a> (MIT license)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The agent harness—comprising prompts, tools, memory, and orchestration logic surrounding the model—has emerged as the central engineering abstraction for LLM-based agents, yet its design remains informal. This paper provides a formal theory using the <strong>ArchAgents categorical architecture triple (G, Know, Φ)</strong>, mapping the four externalization pillars (memory, skills, protocols, harness) to categorical structures. Compiler functors are validated against five frameworks.</p><blockquote><p>&quot;If you&#39;re not the model, you&#39;re the harness.&quot;</p></blockquote><hr><h2 id="core-framework-the-architecture-triple" tabindex="-1">Core Framework: The Architecture Triple <a class="header-anchor" href="#core-framework-the-architecture-triple" aria-label="Permalink to &quot;Core Framework: The Architecture Triple&quot;">​</a></h2><p>Three components of the ArchAgents categorical triple:</p><table tabindex="0"><thead><tr><th>Component</th><th>Description</th><th>Implementation</th></tr></thead><tbody><tr><td><strong>G (Syntactic Wiring)</strong></td><td>Directed graph of information flow between modules and typed ports</td><td>WiringDiagram, typed ports</td></tr><tr><td><strong>Know (Knowledge Structure)</strong></td><td>Structural invariants encoded as replay-verifiable certificates (priority gating, convergence checks, quality-based escalation)</td><td>SkillStage, PatternTemplate</td></tr><tr><td><strong>Φ (Deployment Map)</strong></td><td>Mapping from abstract capability slots to concrete model implementations</td><td>Model parametricity</td></tr></tbody></table><hr><h2 id="four-pillars-mapped-to-categorical-components" tabindex="-1">Four Pillars Mapped to Categorical Components <a class="header-anchor" href="#four-pillars-mapped-to-categorical-components" aria-label="Permalink to &quot;Four Pillars Mapped to Categorical Components&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Externalization Pillar</th><th>Categorical Role</th><th>Implementation</th></tr></thead><tbody><tr><td>Memory</td><td>Coalgebraic state (coalgebra over endofunctor)</td><td>BiTemporalMemory, RunContext</td></tr><tr><td>Skills</td><td>Operad-composed objects (n-ary morphisms)</td><td>SkillStage, PatternTemplate</td></tr><tr><td>Protocols</td><td>Syntactic wiring G</td><td>WiringDiagram, typed ports</td></tr><tr><td>Harness Engineering</td><td>Full Architecture (G, Know, Φ)</td><td>SkillOrganism + components</td></tr></tbody></table><p><strong>Atomic Skills via Operad Composition</strong> (Ma et al.): Five foundational coding skills (localize, edit, test, reproduce, review) compose via:</p><ul><li><strong>Serial (B∘A)</strong>: Sequential pipelines</li><li><strong>Parallel (A⊗B)</strong>: Independent specialist execution</li><li><strong>Trace (Tr(A))</strong>: Feedback loops for homeostatic control</li></ul><hr><h2 id="certificate-preservation-mechanism" tabindex="-1">Certificate Preservation Mechanism <a class="header-anchor" href="#certificate-preservation-mechanism" aria-label="Permalink to &quot;Certificate Preservation Mechanism&quot;">​</a></h2><p>&quot;Structural replay&quot; rather than output-layer verification. Compilers check:</p><ol><li>Graph structure preservation (source stages ⊆ target stages)</li><li>Certificate theorem identity and parameter preservation</li><li>Deployment map compatibility</li></ol><hr><h2 id="compiler-functors-five-frameworks-validated" tabindex="-1">Compiler Functors: Five Frameworks Validated <a class="header-anchor" href="#compiler-functors-five-frameworks-validated" aria-label="Permalink to &quot;Compiler Functors: Five Frameworks Validated&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Framework</th><th>Mapping Style</th><th>Certificate Preservation</th></tr></thead><tbody><tr><td>Swarms</td><td>1:1 graph mapping</td><td>3/3 (100%)</td></tr><tr><td>DeerFlow</td><td>Hub-and-spoke reshaping</td><td>3/3 (100%)</td></tr><tr><td>Ralph</td><td>Hat pattern conversion</td><td>3/3 (100%)</td></tr><tr><td>Scion</td><td>Adds watcher agent</td><td>3/3 (100%)</td></tr><tr><td>LangGraph</td><td>Per-stage execution model</td><td>Preserved via per-stage run()</td></tr></tbody></table><p><strong>LangGraph compiler</strong> achieved functional equivalence with the native runtime—strongest validation result.</p><hr><h2 id="experimental-results" tabindex="-1">Experimental Results <a class="header-anchor" href="#experimental-results" aria-label="Permalink to &quot;Experimental Results&quot;">​</a></h2><h3 id="_1-escalation-experiment-model-parametricity" tabindex="-1">1. Escalation Experiment (Model-Parametricity) <a class="header-anchor" href="#_1-escalation-experiment-model-parametricity" aria-label="Permalink to &quot;1. Escalation Experiment (Model-Parametricity)&quot;">​</a></h3><p>Single-stage code review task:</p><ul><li><strong>Fast tier</strong>: Phi-3 Mini (3.8B)</li><li><strong>Deep tier</strong>: Gemma 4 (27B MoE)</li><li><strong>Result</strong>: Quality-based escalation fires correctly when fast model scores below 0.60 threshold → triggers deep-model re-execution</li></ul><p><strong>Demonstrates</strong>: Control path is model-parametric (harness-level, not model-specific).</p><h3 id="_2-swe-bench-lite-analysis-gemma-4-8b" tabindex="-1">2. SWE-bench-lite Analysis (Gemma 4, 8B) <a class="header-anchor" href="#_2-swe-bench-lite-analysis-gemma-4-8b" aria-label="Permalink to &quot;2. SWE-bench-lite Analysis (Gemma 4, 8B)&quot;">​</a></h3><ul><li>10 instances, three conditions (baseline prompt, organism pipeline, LangGraph)</li><li><strong>0 resolved</strong> across all conditions after sanitizer filtered malformed diffs</li><li><strong>Key finding</strong>: &quot;8B format discipline is the ceiling&quot; — model cannot reliably produce git-apply-clean unified diffs regardless of harness complexity</li></ul><p><strong>Phase C (deepseek-r1:8b)</strong>: Cross-model validation with retry-on-reject:</p><ul><li>0/30 evaluated across conditions</li><li>Zero retry-recovered patches despite targeted reason-code prompts</li><li><strong>Confirms</strong>: Retry helps near-correct models; cannot overcome capability gaps at 8B scale</li></ul><hr><h2 id="key-claims-and-limitations" tabindex="-1">Key Claims and Limitations <a class="header-anchor" href="#key-claims-and-limitations" aria-label="Permalink to &quot;Key Claims and Limitations&quot;">​</a></h2><h3 id="what-the-correspondence-provides" tabindex="-1">What the Correspondence Provides <a class="header-anchor" href="#what-the-correspondence-provides" aria-label="Permalink to &quot;What the Correspondence Provides&quot;">​</a></h3><ol><li>Formal language for harness specification (Know certificates with verifiable semantics)</li><li>Mechanically verified preservation guarantees across compiler functors</li><li>Type-safe composition rules via operad structure</li><li>Model parametricity demonstrated experimentally</li></ol><h3 id="acknowledged-limitations" tabindex="-1">Acknowledged Limitations <a class="header-anchor" href="#acknowledged-limitations" aria-label="Permalink to &quot;Acknowledged Limitations&quot;">​</a></h3><ul><li><strong>Static snapshot</strong>: No modeling of harness evolution/adaptation over time</li><li><strong>Single implementation</strong>: Operon is the only reference; independent implementations needed</li><li><strong>Certificate scope</strong>: Covers structural invariants, not behavioral properties (e.g., hallucination prevention)</li><li><strong>Escalation scale</strong>: Two models on one task; larger studies needed</li><li><strong>SWE-bench ceiling</strong>: 0 resolved at 8B; &quot;transfer value demonstrated in preservation, not task-resolution gains&quot;</li></ul><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>Categorical architecture is the formal theory underlying harness engineering practice. The Architecture triple provides the mathematical substrate for what practitioners already do empirically.</p><p><strong>Practical implication</strong>: Specify certificates before building, verify preservation before compiling, check type compatibility before composing.</p>',43)])])}const m=t(o,[["render",n]]);export{g as __pageData,m as default};
